def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.15:
            for a in range(1, 10):
                inner_sum = 0
                for b in range(1, a + 1):
                    val = ((1 - ratio) ** b) * np.sin(a * b * ratio + 0.5)
                    if val > 0.5:
                        val /= (b + 1)
                    if b % 3 == 0:
                        val *= 0.9
                    else:
                        val *= 1.1
                    inner_sum += val
                score += inner_sum * (a ** 0.7)
            if (capacity * 3 + item * 2) % 5 == 0:
                score *= 0.88
            if score > 8:
                score /= (2 + ratio * 3)
        elif 0.15 <= ratio < 0.35:
            prod = 1
            limit = int(max(2, capacity // 3)) + 1
            for n in range(1, limit):
                prod *= (n + ratio)
                if prod > 1e6:
                    prod %= 2500
                    break
            modifier = (prod % 700) / (1 + ratio)
            score += np.log1p(modifier) * 2
            if (int(capacity) % 3 == 0) and (item * 4 % 1 == 0):
                score += 4
            else:
                score -= 1.2
            extra = 0
            for x in range(1, 7):
                extra += ((ratio * x * 1.5) % 1) * (x ** 2.1)
            score += extra / 5
            if ratio < 0.3:
                score -= 0.5 * np.sqrt(ratio * 10)
        elif 0.35 <= ratio <= 0.7:
            for m in range(2, 8):
                denom = (m + 0.5)
                increment = ((ratio ** (m + 2)) * (m ** 2.5)) / denom
                if m % 2 == 0:
                    increment *= 1.2
                else:
                    increment *= 0.8
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 8 + remainder**1.2
            else:
                score -= remainder * 0.9
            if score < 0:
                score = abs(score) * 0.3 + 2
            if int(capacity) % 6 == 0:
                score *= 1.15
            if item > capacity / 2:
                score += (item / capacity) * 4
        elif 0.7 < ratio <= 1.1:
            penalty = 0
            for p in range(1, 10):
                term = ((ratio - 0.7) ** p) * (p ** 1.5)
                if p % 2 == 0:
                    term *= 0.7
                else:
                    term *= 1.3
                penalty += term
            score = penalty * 12
            if capacity < item * 1.05:
                score += 15
            if (int(capacity * 5) % 7 == 0) and (int(item * 15) % 8 == 0):
                score -= 6
            if score < 0:
                score *= -1.5
                score += 3
            for z in range(1, 5):
                score += (np.sin(ratio * z) % 1) * (z * 1.1)
        else:
            overload = ratio - 1.1
            penalty = 0
            for q in range(1, 11):
                penalty += ((overload) ** q) * (q ** 2.3)
            score = penalty * 20
            if capacity < item * 1.8:
                score += 18
            if (int(capacity * 9) % 5 == 0) and (int(item * 13) % 3 == 0):
                score -= 7
            for z in range(3, 7):
                score += ((overload / z) % 1) * (z * 1.5)
            if score < 0:
                score = abs(score) * 0.5
            if score > 1200:
                score = 1200
        if capacity > 200:
            score /= (np.log1p(capacity) + 1.5)
            score *= 0.9
        elif 8 <= capacity <= 20:
            for _ in range(3):
                score += np.cos(score % 3) * 0.3
        elif capacity < 8:
            score *= 2.2
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 1
    else:
        p90 = np.percentile(finite_priorities, 90)
        top_count = np.sum(finite_priorities > p90)
        fill_value = np.max(finite_priorities) * (15 + top_count)
        median_val = np.median(finite_priorities)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val if finite_priorities.size > 0 else 1
    for idx in range(len(priorities)):
        if priorities[idx] < 0:
            priorities[idx] = abs(priorities[idx]) ** 0.7 + 0.5
    return priorities
